// Classify an inbound email from VoipLine/VoipCloud about a Request Numbers order.
const d = $json;
const from = String((d.from && d.from.emailAddress && d.from.emailAddress.address) || d.sender || d.fromAddress || '').toLowerCase();
const subject = String(d.subject || '');
const bodyText = String((d.body && d.body.content) || d.bodyPreview || d.text || '');
const blob = (subject + ' ' + bodyText).toLowerCase();
const isVoipline = from.includes('voipcloud') || from.includes('voipline') || blob.includes('voipcloud') || blob.includes('voipline');

// Extract an Australian DID from the body (matches 0xxxxxxxxx, 61xxxxxxxxx or +61...).
const compact = bodyText.replace(/[\s\-()]/g, '');
const m = compact.match(/(?:\+?61|0)[2-8]\d{8}/);
const did = m ? m[0].replace(/^\+?61/, '0') : '';

let classification = 'ignore';
if (isVoipline) {
  if (did && /(sourced|provisioned|available|confirmed|allocated|ready|activated)/.test(blob)) {
    classification = 'confirmation';
  } else if (/(instead|alternative|suggest|different exchange|propose|nearest)/.test(blob)) {
    classification = 'counter_suggestion';
  }
}

return [{ json: { message_id: d.id, from_address: from, subject: subject, classification: classification, extracted_did: did, body_preview: d.bodyPreview || '' } }];

// CONFIRMATION received - a number was sourced. Resume Workflow 1 Path B from the 3CX setup step.
// CORRELATION: at live integration the pending subscriber (prison/mobile/email/subscription) is
// looked up from the Path B pending store keyed by the order. Mocked here with the extracted DID.
const d = $json;
const did = String(d.extracted_did || '').replace(/^\+/, '');
const extension = 103; // live integration queries 3CX for next free extension
const threeCX = {
  mocked: true,
  success: true,
  resumed_from: 'WF1 Path B',
  steps: [
    { step: 'create_extension', extension: extension, ok: true },
    { step: 'assign_did', did: did, ok: true },
    { step: 'configure', also_ring_my_mobile: true, no_answer_timeout_seconds: 15, forward_external_calls_to: 'Send Busy', voicemail_enabled: false, ok: true },
    { step: 'set_outbound_caller_id', outbound_caller_id: did, ok: true }
  ]
};
return [{ json: { ...d, did: did, threeCX_extension: extension, threeCX } }];

// Notify owner the sourced number was provisioned. Customer SMS/email send once the pending
// subscriber record is correlated (live integration) - mobile/email not present on the email itself.
const helpers = this.helpers;
const d = $json;
const auth = 'Basic ' + Buffer.from($env.CLICKSEND_USERNAME + ':' + $env.CLICKSEND_API_KEY).toString('base64');
const text = 'PRISONCALL: VoipLine sourced number ' + d.did + '. 3CX extension provisioned (mock). Confirm subscriber correlation and customer notification.';
const resp = await helpers.httpRequest({
  method: 'POST',
  url: 'https://rest.clicksend.com/v3/sms/send',
  headers: { Authorization: auth, 'Content-Type': 'application/json' },
  body: { messages: [{ source: 'n8n', from: $env.CLICKSEND_DEDICATED_NUMBER, to: $env.OWNER_MOBILE, body: text }] },
  json: true
});
return [{ json: { ...d, owner_sms: resp } }];
